using System;
using System.Runtime.InteropServices;

public static class NativeCompression
{
    [DllImport("compresslib", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
    public static extern int CompressBuffer(
        byte[] input,
        UIntPtr inputLen,
        byte[] output,
        UIntPtr outputLen,
        out UIntPtr bytesWritten);

    [DllImport("compresslib", CallingConvention = CallingConvention.Cdecl, EntryPoint = "compress_buffer", ExactSpelling = true)]
    private static extern int NativeCompressBuffer(
        byte[] input,
        UIntPtr inputLen,
        byte[] output,
        UIntPtr outputLen,
        out UIntPtr bytesWritten);

    /// <summary>
    /// Compresses the input buffer into the output buffer.
    /// </summary>
    /// <param name="input">Source data to compress.</param>
    /// <param name="output">Destination buffer for compressed data.</param>
    /// <param name="bytesWritten">Number of bytes written to the output buffer.</param>
    /// <returns>Status code from the native library (0 typically indicates success).</returns>
    public static int Compress(byte[] input, byte[] output, out int bytesWritten)
    {
        if (input == null) throw new ArgumentNullException(nameof(input));
        if (output == null) throw new ArgumentNullException(nameof(output));

        int result = NativeCompressBuffer(
            input,
            new UIntPtr((uint)input.Length),
            output,
            new UIntPtr((uint)output.Length),
            out UIntPtr written);

        bytesWritten = (int)(uint)written;
        return result;
    }
}

